// src/pages/Dashboard.js
import React, { useEffect, useRef, useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { useNavigate } from 'react-router-dom';
import { gsap } from 'gsap';
import { useAuth } from '../hooks/useAuth';
import api from '../services/api';
import { FaParking, FaCar, FaCheckCircle, FaChartBar, FaClock, FaFire } from 'react-icons/fa';

function CountdownTimer({ checkIn, durationHours }) {
  const [remaining, setRemaining] = useState('');

  useEffect(() => {
    if (!checkIn) return;
    const end = new Date(checkIn).getTime() + (durationHours || 1) * 3600000;
    const tick = () => {
      const diff = end - Date.now();
      if (diff <= 0) { setRemaining('Expired'); return; }
      const h = Math.floor(diff / 3600000);
      const m = Math.floor((diff % 3600000) / 60000);
      const s = Math.floor((diff % 60000) / 1000);
      setRemaining(`${h}h ${String(m).padStart(2,'0')}m ${String(s).padStart(2,'0')}s`);
    };
    tick();
    const id = setInterval(tick, 1000);
    return () => clearInterval(id);
  }, [checkIn, durationHours]);

  const expiring = remaining !== 'Expired' && remaining.startsWith('0h');
  return (
    <div style={{
      display:'flex', alignItems:'center', gap:10, padding:'8px 12px',
      borderRadius:12, background: expiring ? 'rgba(239,68,68,0.08)' : 'rgba(0,210,255,0.06)',
      border: `1px solid ${expiring ? 'rgba(239,68,68,0.18)' : 'rgba(0,210,255,0.12)'}`}}>
      <FaClock size={14} color={expiring ? '#ef4444' : '#00d2ff'} />
      <div style={{ fontWeight:800, color: expiring ? '#ef4444' : '#00d2ff', fontSize:13 }}>{remaining || '—'}</div>
      <div style={{ fontSize:11, color:'var(--text-muted)' }}>remaining</div>
    </div>
  );
}

function OccupancyHeatmap({ slots }) {
  const hours = Array.from({ length: 24 }, (_, i) => i);
  const heat = hours.map(h => {
    if (h >= 7 && h <= 9) return 0.9;
    if (h >= 12 && h <= 14) return 0.75;
    if (h >= 17 && h <= 19) return 0.85;
    if (h >= 22 || h <= 5) return 0.12;
    return 0.3 + Math.random()*0.28;
  });

  const color = v => v >= 0.8 ? '#ef4444' : v >= 0.6 ? '#f59e0b' : v >= 0.3 ? '#3b82f6' : '#10b981';

  return (
    <div style={{ display:'flex', flexDirection:'column', gap:12 }}>
      <div style={{ display:'flex', alignItems:'flex-end', gap:8, height:110 }}>
        {heat.map((v,i) => (
          <div key={i} title={`${i}:00 — ${Math.round(v*100)}%`} style={{
            flex: 1, height: `${Math.max(6, v*100)}%`, minWidth:6,
            background: color(v), borderRadius:6, transition:'height 0.45s ease',
            boxShadow:'0 8px 20px rgba(0,0,0,0.35)'
          }} />
        ))}
      </div>
      <div style={{ display:'flex', justifyContent:'space-between', fontSize:12, color:'var(--text-muted)' }}>
        <span>12am</span><span>6am</span><span>12pm</span><span>6pm</span><span>11pm</span>
      </div>
      <div style={{ display:'flex', gap:12, marginTop:2, alignItems:'center', fontSize:12 }}>
        <div style={{ display:'flex', alignItems:'center', gap:8 }}>
          <div style={{ width:10, height:10, background:'#10b981', borderRadius:3 }} /> Low
        </div>
        <div style={{ display:'flex', alignItems:'center', gap:8 }}>
          <div style={{ width:10, height:10, background:'#3b82f6', borderRadius:3 }} /> Medium
        </div>
        <div style={{ display:'flex', alignItems:'center', gap:8 }}>
          <div style={{ width:10, height:10, background:'#f59e0b', borderRadius:3 }} /> High
        </div>
        <div style={{ display:'flex', alignItems:'center', gap:8 }}>
          <div style={{ width:10, height:10, background:'#ef4444', borderRadius:3 }} /> Peak
        </div>
      </div>
    </div>
  );
}

export default function Dashboard() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const containerRef = useRef(null);

  const { data: slots = [], isLoading } = useQuery({
    queryKey: ['slots'],
    queryFn: () => api.get('/slots').then(r => r.data).catch(() => []),
    refetchInterval: 15000,
  });

  const { data: bookings = [] } = useQuery({
    queryKey: ['bookings'],
    queryFn: () => api.get('/bookings').then(r => r.data).catch(() => []),
    enabled: !!user,
  });

  useEffect(() => {
    if (!containerRef.current || isLoading) return;
    const items = containerRef.current.querySelectorAll('.dash-anim');
    gsap.fromTo(items, { y: 20, opacity: 0 }, { y: 0, opacity: 1, duration: 0.55, stagger: 0.06 });
  }, [isLoading, slots.length]);

  const available = slots.filter(s => s.status === 'AVAILABLE').length;
  const occupied = slots.filter(s => s.status === 'OCCUPIED').length;
  const reserved = slots.filter(s => s.status === 'RESERVED').length;
  const total = Math.max(1, slots.length);
  const occupancyPct = Math.round((occupied / total) * 100);

  const myActiveBooking = bookings.find(b => b.status === 'ACTIVE' && b.user_id === user?.id);
  const mySlot = myActiveBooking ? slots.find(s => s.id === myActiveBooking.slot_id) : null;

  const STATS = [
    { label: 'Available', value: available, icon: <FaCheckCircle />, cls: 'green' },
    { label: 'Occupied', value: occupied, icon: <FaCar />, cls: 'red' },
    { label: 'Reserved', value: reserved, icon: <FaParking />, cls: 'yellow' },
    { label: 'Total Slots', value: total, icon: <FaChartBar />, cls: 'primary' },
  ];

  if (isLoading) {
    return (
      <div style={{ minHeight: '60vh', display:'flex', justifyContent:'center', alignItems:'center' }}>
        <div className="suprs-spinner" />
      </div>
    );
  }

  return (
    <div className="page page-dashboard" ref={containerRef} role="main" aria-label="Dashboard">
      <div className="dashboard-shell">
        <main className="dashboard-main">
          <div className="dash-anim" style={{ marginBottom: 18 }}>
            <h1 style={{ margin: 0, fontWeight: 900, fontSize: '2.0rem' }}>
              👋 Welcome back, <span className="text-gradient">{user?.name || user?.email?.split('@')[0]}</span>
            </h1>
            <p style={{ marginTop:6, color:'var(--text-muted)' }}>
              {new Date().toLocaleDateString('en-US', { weekday:'long', year:'numeric', month:'long', day:'numeric' })} · Real-time parking status
            </p>
          </div>

          {myActiveBooking && mySlot && (
            <div className="dash-anim glass-card glow-primary" style={{ marginBottom: 20 }}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', gap:12, flexWrap:'wrap' }}>
                <div style={{ display:'flex', gap:12, alignItems:'center' }}>
                  <div style={{ width:56, height:56, borderRadius:16, background:'rgba(0,210,255,0.08)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:26 }}>
                    🅿️
                  </div>
                  <div>
                    <div style={{ fontWeight:900, fontSize:16 }}>{`Active Booking — Slot ${mySlot.slot_number}`}</div>
                    <div style={{ color:'var(--text-muted)', fontSize:13 }}>
                      {myActiveBooking.duration_hours}h · ${Number(myActiveBooking.total_amount||0).toFixed(2)} · <strong style={{ color: myActiveBooking.payment_status === 'PAID' ? 'var(--green)' : 'var(--yellow)' }}>{myActiveBooking.payment_status}</strong>
                    </div>
                  </div>
                </div>
                <CountdownTimer checkIn={myActiveBooking.check_in || myActiveBooking.booked_at} durationHours={myActiveBooking.duration_hours || 1} />
              </div>
            </div>
          )}

          <div className="dash-anim glass-card" style={{ padding: '1.25rem' }}>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', gap:12 }}>
              <h4 style={{ margin: 0, fontWeight: 800 }}>🅿️ Live Parking Map</h4>
              <button className="btn-suprs" onClick={() => navigate('/booking')}>+ Book a Slot</button>
            </div>

            <div className="parking-grid" style={{ marginTop: 18 }}>
              {slots.length === 0 ? (
                <div style={{ padding:36, borderRadius:12, background:'rgba(255,255,255,0.01)', color:'var(--text-muted)', textAlign:'center', width:'100%' }}>
                  No slots configured yet. Ask an admin to add slots.
                </div>
              ) : (
                slots.map(slot => {
                  const st = (slot.status || 'AVAILABLE').toLowerCase();
                  return (
                    <div key={slot.id} className={`slot-box ${st}`} onClick={() => st === 'available' && navigate('/booking')}>
                      <div style={{ display:'flex', alignItems:'center', gap:12 }}>
                        <div style={{ fontSize:32 }}>{st === 'available' ? '🟢' : st === 'occupied' ? '🔴' : '🟡'}</div>
                        <div>
                          <div className="slot-number">Slot {slot.slot_number}</div>
                          <div className="slot-meta" style={{ marginTop:6 }}>{slot.location || ''}</div>
                        </div>
                      </div>
                      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center' }}>
                        {slot.price_per_hour ? <div className="slot-meta">${slot.price_per_hour}/hr</div> : <div/>}
                        <div className={`slot-status-badge ${st}`}>{slot.status}</div>
                      </div>
                    </div>
                  );
                })
              )}
            </div>
          </div>
        </main>

        <aside className="dashboard-side">
          <div className="dash-anim" style={{ marginBottom: 16 }}>
            <div style={{ display:'grid', gridTemplateColumns:'repeat(2,1fr)', gap:12 }}>
              {STATS.map(s => (
                <div key={s.label} className={`stat-card ${s.cls}`} style={{ minHeight:120 }}>
                  <div className="stat-icon" style={{ background: s.cls === 'green' ? 'rgba(16,185,129,0.06)' : s.cls === 'red' ? 'rgba(239,68,68,0.06)' : 'rgba(0,210,255,0.06)' }}>
                    {s.icon}
                  </div>
                  <div>
                    <div className="stat-value">{s.value}</div>
                    <div className="stat-label">{s.label}</div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="dash-anim glass-card" style={{ marginBottom:16 }}>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center' }}>
              <h5 style={{ margin:0, fontWeight:700 }}>🔥 Occupancy Rate</h5>
              <div style={{ fontWeight:900, fontSize:20, color: occupancyPct >= 80 ? 'var(--red)' : occupancyPct >= 50 ? 'var(--yellow)' : 'var(--green)' }}>
                {occupancyPct}%
              </div>
            </div>
            <div style={{ marginTop:12 }}>
              <div className="progress-bar-track">
                <div className="progress-bar-fill" style={{
                  width:`${occupancyPct}%`,
                  background: occupancyPct >= 80 ? 'linear-gradient(90deg,#ef4444,#dc2626)' : occupancyPct >= 50 ? 'linear-gradient(90deg,#f59e0b,#d97706)' : 'linear-gradient(90deg,#10b981,#059669)'
                }} />
              </div>
              <div style={{ display:'flex', justifyContent:'space-between', fontSize:12, color:'var(--text-muted)', marginTop:10 }}>
                <span>{available} available</span><span>{occupied} occupied</span>
              </div>
            </div>
          </div>

          <div className="dash-anim glass-card heatmap-card" style={{ padding: '1.1rem' }}>
            <h5 style={{ margin:0, fontWeight:700, marginBottom:12 }}>🔥 Hourly Demand Heatmap</h5>
            <OccupancyHeatmap slots={slots} />
          </div>
        </aside>
      </div>
    </div>
  );
}